func getMarkerColor(todoType string, markers []db.TodoMarker) string {
	t := strings.ToUpper(todoType)
	if t == "TASK" {
		return "#10b981"
	}
	for _, m := range markers {
		if m.Marker == t {
			return m.Color
		}
	}
	if t == "FIXME" {
		return "#f59e0b"
	}
	if t == "BUG" {
		return "#ef4444"
	}
	return "#3b82f6"
}

func getTodoIcon(todo processor.TodoItem, markers []db.TodoMarker) string {
	t := strings.ToUpper(todo.Type)
	if t == "TASK" {
		if todo.Status == "completed" {
			return "✓"
		}
		return "⬜"
	}
	if t == "FIXME" {
		return "🟡"
	}
	if t == "BUG" {
		return "🔴"
	}
	return "🔵"
}

