func toggleFolder(id string) templ.ComponentScript {
	return templ.ComponentScript{
		Name: `__templ_toggleFolder_24c0`,
		Function: `function __templ_toggleFolder_24c0(id){const el = document.getElementById(id);
    const icon = document.getElementById("toggle-icon-" + id);
    if (el) {
        if (el.classList.contains("expanded")) {
            el.classList.remove("expanded");
            el.style.display = "none";
            if(icon) icon.textContent = "▶";
        } else {
            el.classList.add("expanded");
            el.style.display = "block";
            if(icon) icon.textContent = "▼";
        }
    }
}`,
		Call:       templ.SafeScript(`__templ_toggleFolder_24c0`, id),
		CallInline: templ.SafeScriptInline(`__templ_toggleFolder_24c0`, id),
	}
}

